@import url('https://fonts.googleapis.com/css2?family=Noto+Sans+KR:wght@300;400;500;700;900&display=swap');

* {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

html {
    scroll-behavior: smooth;
}

body {
    font-family: 'Noto Sans KR', sans-serif;
    background: #f4f5f7;
    font-size: 13px;
    color: #111;
}

/* ============================================
   TOP BAR
   ============================================ */

.topbar {
    height: 36px;
    background: #f9f9f9;
    border-bottom: 1px solid #e0e0e0;
    display: flex;
    align-items: center;
    justify-content: flex-end;
    padding: 0 24px;
    gap: 8px;
    font-size: 12px;
    color: #555;
}

.tb-user {
    display: inline-flex;
    align-items: center;
    gap: 5px;
    border: 1px solid #ccc;
    border-radius: 4px;
    padding: 3px 10px;
    background: #fff;
    font-size: 12px;
    color: #888;
}

.tb-apply {
    background: #1a56db;
    color: #fff;
    border: none;
    border-radius: 4px;
    padding: 4px 14px;
    font-size: 12px;
    font-weight: 700;
    cursor: pointer;
    font-family: inherit;
}

.tb-apply:hover {
    background: #1648c2;
}

/* ============================================
   HEADER
   ============================================ */

.header {
    background: #fff;
    border-bottom: 1px solid #e8e8e8;
    padding: 10px 24px;
    display: flex;
    align-items: center;
}

.logo {
    font-size: 26px;
    font-weight: 900;
    letter-spacing: -0.04em;
    color: #0a1628;
    margin-right: 22px;
}

.logo span {
    color: #1a56db;
}

.search-bar {
    flex: 1;
    max-width: 500px;
    border: 2px solid #cbd5e1;
    border-radius: 24px;
    display: flex;
    align-items: center;
    padding: 7px 18px;
    background: #fff;
}

.search-bar input {
    border: none;
    outline: none;
    flex: 1;
    font-size: 13px;
    font-family: inherit;
    color: #333;
}

.search-bar input::placeholder {
