// 자연어 검색 기능
// ============================================

let searchQueries = [];
let searchDebounceTimer = null;

/**
 * 검색 초기화 - 페이지 로드 시 실행
 */
async function initSearch() {
  try {
    const response = await fetch('../data/search_queries.json');
